import{_ as e,o,c as r,ag as i}from"./chunks/framework.6MCaaFDc.js";const u=JSON.parse('{"title":"Online Services","description":"","frontmatter":{},"headers":[],"relativePath":"theory/internet/online-services.md","filePath":"theory/internet/online-services.md"}'),a={name:"theory/internet/online-services.md"};function s(n,t,d,l,c,h){return o(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="online-services" tabindex="-1">Online Services <a class="header-anchor" href="#online-services" aria-label="Permalink to &quot;Online Services&quot;">​</a></h1><p>The internet has moved almost everything online — banking, shopping, collaboration, entertainment, and communication. Understanding what services exist, how they work, and what the trade-offs are is essential for both the theory exam and everyday digital life.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 12</p><p>Online services and applications (cloud storage, online apps, cookies, e-commerce) are primarily Grade 12 content, building on Grade 11 internet knowledge.</p></div><hr><h2 id="categories-of-online-services" tabindex="-1">Categories of Online Services <a class="header-anchor" href="#categories-of-online-services" aria-label="Permalink to &quot;Categories of Online Services&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Description</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Email</strong></td><td>Electronic messaging</td><td>Gmail, Outlook</td></tr><tr><td><strong>Cloud storage</strong></td><td>Store and access files remotely</td><td>Google Drive, OneDrive, Dropbox</td></tr><tr><td><strong>Online productivity</strong></td><td>Web-based office tools</td><td>Google Docs, Microsoft 365</td></tr><tr><td><strong>E-commerce</strong></td><td>Online shopping and payments</td><td>Amazon, Takealot, Woolworths</td></tr><tr><td><strong>Social media</strong></td><td>Share content, communicate</td><td>Facebook, Instagram, X</td></tr><tr><td><strong>Streaming</strong></td><td>Audio and video on demand</td><td>Netflix, YouTube, Spotify</td></tr><tr><td><strong>Online banking</strong></td><td>Manage finances online</td><td>FNB, Nedbank, Capitec</td></tr><tr><td><strong>Search engines</strong></td><td>Find information</td><td>Google, Bing</td></tr><tr><td><strong>Online learning</strong></td><td>Educational platforms</td><td>Khan Academy, Coursera</td></tr><tr><td><strong>Video conferencing</strong></td><td>Real-time video calls</td><td>Zoom, Teams, Google Meet</td></tr></tbody></table><hr><h2 id="cloud-storage" tabindex="-1">Cloud Storage <a class="header-anchor" href="#cloud-storage" aria-label="Permalink to &quot;Cloud Storage&quot;">​</a></h2><p><strong>Cloud storage</strong> saves files on remote servers, accessible from any internet-connected device.</p><table tabindex="0"><thead><tr><th>Service</th><th>Provider</th><th>Free Storage</th></tr></thead><tbody><tr><td>Google Drive</td><td>Google</td><td>15 GB</td></tr><tr><td>OneDrive</td><td>Microsoft</td><td>5 GB</td></tr><tr><td>Dropbox</td><td>Dropbox</td><td>2 GB</td></tr><tr><td>iCloud</td><td>Apple</td><td>5 GB</td></tr><tr><td>Amazon Drive</td><td>Amazon</td><td>5 GB</td></tr></tbody></table><p><strong>Advantages of cloud storage:</strong></p><ul><li>Access files from any device, anywhere</li><li>Automatic backup — files safe if device stolen/damaged</li><li>Easy sharing and collaboration</li><li>Scales — pay for more storage as needed</li><li>No hardware to buy or maintain</li></ul><p><strong>Disadvantages:</strong></p><ul><li>Internet required for access</li><li>Ongoing subscription cost for large storage</li><li>Privacy concerns — third party holds your data</li><li>Vendor lock-in — difficult to switch providers</li><li>Data sovereignty — your data may be stored in another country</li></ul><hr><h2 id="online-applications-vs-desktop-applications" tabindex="-1">Online Applications vs Desktop Applications <a class="header-anchor" href="#online-applications-vs-desktop-applications" aria-label="Permalink to &quot;Online Applications vs Desktop Applications&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Online App (SaaS)</th><th>Desktop App</th></tr></thead><tbody><tr><td>Installation</td><td>None — runs in browser</td><td>Must install on device</td></tr><tr><td>Updates</td><td>Automatic — always latest version</td><td>Manual or prompted</td></tr><tr><td>Access</td><td>Any device with browser</td><td>Only devices where installed</td></tr><tr><td>Internet required</td><td>Yes</td><td>Usually no</td></tr><tr><td>Storage</td><td>Cloud</td><td>Local</td></tr><tr><td>Collaboration</td><td>Real-time multi-user editing</td><td>Usually not</td></tr><tr><td>Offline use</td><td>Limited</td><td>Full</td></tr><tr><td>Examples</td><td>Google Docs, Canva, Figma</td><td>Microsoft Word, Photoshop</td></tr></tbody></table><p><strong>Google Docs vs Microsoft Word:</strong></p><table tabindex="0"><thead><tr><th></th><th>Google Docs</th><th>Microsoft Word</th></tr></thead><tbody><tr><td>Storage</td><td>Google Drive (cloud)</td><td>Local / OneDrive</td></tr><tr><td>Collaboration</td><td>Real-time, built-in</td><td>Requires OneDrive</td></tr><tr><td>Cost</td><td>Free (basic)</td><td>Subscription (Microsoft 365)</td></tr><tr><td>Internet needed</td><td>Yes</td><td>No (desktop)</td></tr><tr><td>Offline use</td><td>Limited</td><td>Full</td></tr></tbody></table><hr><h2 id="e-commerce" tabindex="-1">E-Commerce <a class="header-anchor" href="#e-commerce" aria-label="Permalink to &quot;E-Commerce&quot;">​</a></h2><p><strong>E-commerce</strong> (electronic commerce) is buying and selling goods and services over the internet.</p><h3 id="types-of-e-commerce" tabindex="-1">Types of E-Commerce <a class="header-anchor" href="#types-of-e-commerce" aria-label="Permalink to &quot;Types of E-Commerce&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Description</th><th>Examples</th></tr></thead><tbody><tr><td><strong>B2C</strong></td><td>Business to Consumer</td><td>Amazon, Takealot, Woolworths</td></tr><tr><td><strong>B2B</strong></td><td>Business to Business</td><td>Supplier ordering systems</td></tr><tr><td><strong>C2C</strong></td><td>Consumer to Consumer</td><td>eBay, Gumtree, Facebook Marketplace</td></tr><tr><td><strong>C2B</strong></td><td>Consumer to Business</td><td>Freelancers selling services</td></tr></tbody></table><h3 id="how-online-payments-work" tabindex="-1">How Online Payments Work: <a class="header-anchor" href="#how-online-payments-work" aria-label="Permalink to &quot;How Online Payments Work:&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Customer → Checkout → Payment Gateway → Bank → Authorisation → Merchant</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>Security in e-commerce:</strong></p><ul><li>HTTPS — all transactions encrypted</li><li>PCI-DSS compliance — payment card security standard</li><li>3D Secure — additional bank authentication (OTP)</li><li>SSL certificates — verify merchant identity</li></ul><p><strong>Advantages of e-commerce:</strong></p><ul><li>Open 24/7</li><li>Global reach — sell to anyone, anywhere</li><li>Lower overheads than physical store</li><li>Personalised recommendations</li></ul><p><strong>Disadvantages:</strong></p><ul><li>Cannot see/touch product before purchase</li><li>Returns process can be inconvenient</li><li>Cybersecurity risks (phishing, card fraud)</li><li>Relies on delivery infrastructure</li></ul><hr><h2 id="online-banking" tabindex="-1">Online Banking <a class="header-anchor" href="#online-banking" aria-label="Permalink to &quot;Online Banking&quot;">​</a></h2><p><strong>Online banking</strong> allows account holders to manage finances via a bank&#39;s website or app.</p><p><strong>Features:</strong></p><ul><li>View balances and transactions</li><li>Transfer money between accounts</li><li>Pay bills and recipients</li><li>Apply for loans and credit</li><li>View statements</li></ul><p><strong>Security measures used:</strong></p><ul><li>HTTPS (TLS encryption)</li><li>Two-factor authentication (OTP to phone)</li><li>Session timeouts</li><li>Fraud detection algorithms</li><li>Automatic logout on inactivity</li></ul><hr><h2 id="cookies-in-depth" tabindex="-1">Cookies (in depth) <a class="header-anchor" href="#cookies-in-depth" aria-label="Permalink to &quot;Cookies (in depth)&quot;">​</a></h2><p><strong>Cookies</strong> are small text files stored on a user&#39;s device by websites they visit.</p><h3 id="cookie-types" tabindex="-1">Cookie Types <a class="header-anchor" href="#cookie-types" aria-label="Permalink to &quot;Cookie Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Lifespan</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Session cookie</strong></td><td>Browser session</td><td>Login state, shopping cart</td></tr><tr><td><strong>Persistent cookie</strong></td><td>Days to years</td><td>Preferences, saved login</td></tr><tr><td><strong>First-party cookie</strong></td><td>Site&#39;s own</td><td>Site functionality</td></tr><tr><td><strong>Third-party cookie</strong></td><td>Advertiser&#39;s</td><td>Cross-site tracking for ads</td></tr></tbody></table><h3 id="what-cookies-store" tabindex="-1">What cookies store: <a class="header-anchor" href="#what-cookies-store" aria-label="Permalink to &quot;What cookies store:&quot;">​</a></h3><ul><li>Login session token (keep you logged in)</li><li>Shopping cart contents</li><li>Language and display preferences</li><li>Anonymised tracking ID (for analytics)</li><li>Advertising targeting data</li></ul><h3 id="privacy-and-legislation" tabindex="-1">Privacy and legislation: <a class="header-anchor" href="#privacy-and-legislation" aria-label="Permalink to &quot;Privacy and legislation:&quot;">​</a></h3><ul><li><strong>GDPR</strong> (EU) — must obtain informed consent for non-essential cookies</li><li><strong>POPIA</strong> (SA) — must protect personal information; consent required</li><li>Websites must show a cookie consent banner</li><li>Users can clear, block, or manage cookies in browser settings</li></ul><h3 id="how-advertisers-use-cookies" tabindex="-1">How advertisers use cookies: <a class="header-anchor" href="#how-advertisers-use-cookies" aria-label="Permalink to &quot;How advertisers use cookies:&quot;">​</a></h3><ol><li>Visit website A — advertiser sets cookie with your ID</li><li>Visit website B — same advertiser reads cookie</li><li>Advertiser knows you visited both sites → shows relevant ads</li><li><strong>Retargeting</strong>: shows you ads for products you viewed</li></ol><hr><h2 id="search-engines" tabindex="-1">Search Engines <a class="header-anchor" href="#search-engines" aria-label="Permalink to &quot;Search Engines&quot;">​</a></h2><p><strong>Search engines</strong> index the web and return relevant results for queries.</p><h3 id="how-google-works" tabindex="-1">How Google works: <a class="header-anchor" href="#how-google-works" aria-label="Permalink to &quot;How Google works:&quot;">​</a></h3><ol><li><strong>Crawling</strong> — Googlebot follows links, discovers new pages</li><li><strong>Indexing</strong> — pages analysed and added to database</li><li><strong>Ranking</strong> — algorithm scores pages on ~200 factors: <ul><li>Relevance to query</li><li>Page authority (backlinks)</li><li>Content quality</li><li>Page speed</li><li>Mobile-friendliness</li><li>HTTPS</li></ul></li></ol><p><strong>Personalised search:</strong></p><ul><li>Google uses your search history, location, and preferences</li><li>Two people searching the same term may see different results</li></ul><hr><h2 id="social-media" tabindex="-1">Social Media <a class="header-anchor" href="#social-media" aria-label="Permalink to &quot;Social Media&quot;">​</a></h2><p><strong>Social media</strong> platforms allow users to create profiles, share content, and interact.</p><table tabindex="0"><thead><tr><th>Platform</th><th>Type</th><th>Main content</th></tr></thead><tbody><tr><td>Facebook</td><td>Social network</td><td>Posts, photos, video, groups</td></tr><tr><td>Instagram</td><td>Visual</td><td>Photos, short videos (Reels)</td></tr><tr><td>X (Twitter)</td><td>Microblogging</td><td>Short text posts, news</td></tr><tr><td>TikTok</td><td>Short video</td><td>15-second to 10-minute videos</td></tr><tr><td>YouTube</td><td>Video</td><td>Long-form video</td></tr><tr><td>LinkedIn</td><td>Professional</td><td>Career networking, job listings</td></tr></tbody></table><p><strong>Business use of social media:</strong></p><ul><li>Marketing and advertising (paid ads target specific demographics)</li><li>Customer service</li><li>Brand building</li><li>Influencer partnerships</li></ul><p><strong>Risks:</strong></p><ul><li>Privacy — data used for profiling</li><li>Misinformation spreads rapidly</li><li>Cyberbullying</li><li>Mental health impacts (comparison, addiction by design)</li><li>Data breaches</li></ul><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Cloud storage</strong></td><td>Storing files on remote servers accessible over the internet</td></tr><tr><td><strong>SaaS</strong></td><td>Software as a Service — software delivered via browser</td></tr><tr><td><strong>E-commerce</strong></td><td>Buying and selling goods online</td></tr><tr><td><strong>B2C</strong></td><td>Business to Consumer online commerce</td></tr><tr><td><strong>Cookie</strong></td><td>Small text file stored by a website on your device</td></tr><tr><td><strong>Session cookie</strong></td><td>Temporary cookie — expires when browser closes</td></tr><tr><td><strong>Third-party cookie</strong></td><td>Cookie set by advertiser, not the site you&#39;re visiting</td></tr><tr><td><strong>HTTPS</strong></td><td>HTTP with TLS encryption — essential for secure transactions</td></tr><tr><td><strong>Retargeting</strong></td><td>Showing ads based on sites previously visited</td></tr><tr><td><strong>GDPR</strong></td><td>EU data protection regulation requiring cookie consent</td></tr><tr><td><strong>POPIA</strong></td><td>SA Protection of Personal Information Act</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Give TWO advantages of using online applications (SaaS) over desktop applications&quot;</strong> — no installation needed; automatically updated; accessible from any device; real-time collaboration</p></li><li><p><strong>&quot;What is a cookie? Give TWO uses.&quot;</strong> — small text file stored by a website; uses: keep user logged in; remember preferences; track browsing for advertising; shopping cart contents</p></li><li><p><strong>&quot;Give TWO security measures used in online banking&quot;</strong> — HTTPS (TLS encryption); two-factor authentication (OTP); session timeout; fraud detection</p></li><li><p><strong>&quot;What is e-commerce? Give ONE advantage and ONE disadvantage&quot;</strong> — buying/selling online; advantage: open 24/7, global reach; disadvantage: cannot see product before buying, security risks</p></li><li><p><strong>&quot;What is the difference between a first-party cookie and a third-party cookie?&quot;</strong> — First-party: set by the site you&#39;re visiting (login, preferences); Third-party: set by an advertiser to track you across multiple websites</p></li></ol></div>',71)])])}const p=e(a,[["render",s]]);export{u as __pageData,p as default};
